import React, { useMemo, useState } from "react";
import styled from "@emotion/styled";
import { BiChevronLeft, BiChevronRight } from "react-icons/bi";
import { graphql } from "gatsby";
import { useEffect } from "react";

const Base = styled.div`
  background-color: #161616;
  display: flex;
  flex-direction: column;
  flex: 1 1 auto;
  justify-content: center;
  align-items: center;
  border-radius: 20px;
  height: 300px;
  padding: 1rem;

  @media (max-width: 768px) {
    height: 150px;
  }
`;

const Header = styled.div`
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const ButtonContainer = styled.div`
  display: flex;
  align-items: center;
  justify-content: center;
`;

const ArrowButton = styled.button`
  border: none;
  border-radius: 4px;
  padding: 8px 12px;
  background-color: transparent;
  font-size: 18px;
  cursor: pointer;
  color: #f8f7fa;
`;

const Title = styled.p`
  margin: 0;
  padding: 8px 24px;
  text-align: center;
  color: #f8f7fa;
`;

const Table = styled.table`
  /*   border-collapse: collapse; */
  width: 100%;
  height: 100%;
  border-spacing: 10px;
`;

const TableHeader = styled.thead`
  > tr {
    > th {
      font-size: 12px;
      font-weight: normal;
      color: #f8f7fa;
    }
  }
`;

const TableBody = styled.tbody`
  font-size: 12px;
`;

const TableData = styled.td`
  text-align: center;
  color: #c9c8cc;
  position: relative;
`;

const DisplayDate = styled.div`
  color: ${({ isToday }) => isToday && "#F8F7FA"};
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer;
  color: transparent;
  background-color: ${({ isPostCount }) => (isPostCount == 1 ? "#0e4429" : isPostCount == 2 ? "#006d32" : isPostCount == 3 ? "#26a641" : isPostCount == 4 ? "#39d353" : "#161b22")};
`;

const DAYS = ["SUN", "MON", "TUE", "WED", "THU", "FRI", "SAT"]; // 요일

const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"]; // 달

const isSameDay = (a, b) => {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
};

const DatePicker = ({ edges }) => {
  const [dateList, setDateList] = useState([]);

  useEffect(() => {
    edges.map((v) => {
      const vDate = new Date(v.node.frontmatter.date.replaceAll(".", "/"));
      setDateList((prev) => [...prev, vDate]);
    });
  }, []);

  const isPostCount = (a) => {
    return dateList.filter((e) => e.getFullYear() === a.getFullYear() && e.getMonth() === a.getMonth() && e.getDate() === a.getDate()).length;
  };

  const [selectedDate, setSelectedDate] = useState(new Date()); // 선택한 날짜

  const { year, month, firstDay, lastDay } = useMemo(() => {
    // 선택한 날을 기준으로 첫째 날, 마지막 날, 년, 월
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();

    return {
      year,
      month,
      firstDay: new Date(year, month, 1),
      lastDay: new Date(year, month + 1, 0),
    };
  }, [selectedDate]);

  const selectDate = (date) => {
    // 날짜를 선택한다.
    setSelectedDate(date);
  };

  const pad = () => [...Array(firstDay.getDay()).keys()].map((p) => <TableData key={`pad_${p}`} />); // 해당 월의 첫째 날 전 pad

  const range = () =>
    [...Array(lastDay.getDate()).keys()].map((d) => {
      // 1일부터 마지막 날까지 날짜 표기
      const thisDay = new Date(year, month, d + 1);
      const today = new Date();

      return (
        <TableData key={d} onClick={() => selectDate(thisDay)}>
          <DisplayDate isSelected={isSameDay(selectedDate, thisDay)} isToday={isSameDay(today, thisDay)} isPostCount={isPostCount(thisDay)}>
            {new Date(year, month, d + 1).getDate()}
          </DisplayDate>
        </TableData>
      );
    });

  const render = () => {
    // table data 를 일주일 단위로 줄바꿈
    const items = [...pad(), ...range()];

    const weeks = Math.ceil(items.length / 7);

    return [...Array(weeks).keys()].map((week) => <tr key={`week_${week}`}>{items.slice(week * 7, week * 7 + 7)}</tr>);
  };

  return (
    <Base>
      <Header>
        <ButtonContainer>
          <ArrowButton pos="left" onClick={() => selectDate(new Date(selectedDate.setMonth(selectedDate.getMonth() - 1)))}>
            <BiChevronLeft />
          </ArrowButton>
          <Title>{`${MONTHS[month]} ${year}`}</Title>
          <ArrowButton pos="right" onClick={() => selectDate(new Date(selectedDate.setMonth(selectedDate.getMonth() + 1)))}>
            <BiChevronRight />
          </ArrowButton>
        </ButtonContainer>
      </Header>
      <Table>
        <TableHeader>
          <tr>
            {DAYS.map((day, index) => (
              <th key={day} align="center">
                {day}
              </th>
            ))}
          </tr>
        </TableHeader>
        <TableBody>{render()}</TableBody>
      </Table>
    </Base>
  );
};

export default DatePicker;
